#ifndef KERNEL_H
#define KERNEL_H

#include <ap_int.h>
#include <ap_fixed.h>
#include <hls_math.h>

// Project configuration
#define MATRIX_SIZE 10
#define MAX_ITERATIONS 2000
#define CONVERGENCE_THRESHOLD 164  // 1e-8 * 2^14 ≈ 0.000164 in fixed-point

// Fixed-point configuration from project.yaml
#define TOTAL_BITS 46
#define FRAC_BITS 14
#define INT_BITS (TOTAL_BITS - FRAC_BITS)

// Fixed-point types
typedef ap_fixed<TOTAL_BITS, INT_BITS> fixed_t;
typedef ap_fixed<TOTAL_BITS*2, INT_BITS*2> fixed_mult_t;  // For intermediate products

// Complex number structure
struct complex_t {
    fixed_t re;
    fixed_t im;

    complex_t() : re(0), im(0) {}
    complex_t(fixed_t r, fixed_t i) : re(r), im(i) {}
};

// Complex arithmetic operations
inline complex_t complex_mult(const complex_t& a, const complex_t& b) {
    complex_t result;
    // (a.re + j*a.im) * (b.re + j*b.im) = (a.re*b.re - a.im*b.im) + j*(a.re*b.im + a.im*b.re)
    fixed_mult_t re_prod1 = (fixed_mult_t)a.re * (fixed_mult_t)b.re;
    fixed_mult_t re_prod2 = (fixed_mult_t)a.im * (fixed_mult_t)b.im;
    fixed_mult_t im_prod1 = (fixed_mult_t)a.re * (fixed_mult_t)b.im;
    fixed_mult_t im_prod2 = (fixed_mult_t)a.im * (fixed_mult_t)b.re;

    result.re = (fixed_t)(re_prod1 - re_prod2);
    result.im = (fixed_t)(im_prod1 + im_prod2);
    return result;
}

inline complex_t complex_conj(const complex_t& a) {
    return complex_t(a.re, -a.im);
}

inline complex_t complex_add(const complex_t& a, const complex_t& b) {
    return complex_t(a.re + b.re, a.im + b.im);
}

inline complex_t complex_sub(const complex_t& a, const complex_t& b) {
    return complex_t(a.re - b.re, a.im - b.im);
}

inline fixed_t complex_abs(const complex_t& a) {
    // |a| = sqrt(re^2 + im^2)
    fixed_mult_t re_sq = (fixed_mult_t)a.re * (fixed_mult_t)a.re;
    fixed_mult_t im_sq = (fixed_mult_t)a.im * (fixed_mult_t)a.im;
    fixed_t sum = (fixed_t)(re_sq + im_sq);
    return hls::sqrt((float)sum);  // Using float for sqrt, convert back
}

inline fixed_t complex_angle(const complex_t& a) {
    // angle = atan2(im, re)
    return hls::atan2((float)a.im, (float)a.re);
}

// Top-level kernel function
void kernel_top(
    const ap_int<TOTAL_BITS> matrix_real_in[MATRIX_SIZE * MATRIX_SIZE],
    const ap_int<TOTAL_BITS> matrix_imag_in[MATRIX_SIZE * MATRIX_SIZE],
    ap_int<TOTAL_BITS> eigenvalues_real_out[MATRIX_SIZE],
    ap_int<TOTAL_BITS> eigenvalues_imag_out[MATRIX_SIZE],
    ap_int<TOTAL_BITS> eigenvectors_real_out[MATRIX_SIZE * MATRIX_SIZE],
    ap_int<TOTAL_BITS> eigenvectors_imag_out[MATRIX_SIZE * MATRIX_SIZE],
    ap_uint<12>& iter_count,
    ap_uint<32>& cycles
);

#endif // KERNEL_H

#include "kernel.h"
#include <hls_math.h>

// Convert ap_int to fixed_t
static inline fixed_t int_to_fixed(ap_int<TOTAL_BITS> val) {
    fixed_t result;
    result.range() = val.range(TOTAL_BITS-1, 0);
    return result;
}

// Convert fixed_t to ap_int
static inline ap_int<TOTAL_BITS> fixed_to_int(fixed_t val) {
    ap_int<TOTAL_BITS> result;
    result.range(TOTAL_BITS-1, 0) = val.range();
    return result;
}

// Matrix multiplication: C = A * B (both complex)
static void matrix_mult(
    complex_t A[MATRIX_SIZE][MATRIX_SIZE],
    complex_t B[MATRIX_SIZE][MATRIX_SIZE],
    complex_t C[MATRIX_SIZE][MATRIX_SIZE]
) {
    #pragma HLS INLINE off

    // Initialize output
    for (int i = 0; i < MATRIX_SIZE; i++) {
        for (int j = 0; j < MATRIX_SIZE; j++) {
            #pragma HLS PIPELINE II=1
            C[i][j].re = 0;
            C[i][j].im = 0;
        }
    }

    // Multiply
    for (int i = 0; i < MATRIX_SIZE; i++) {
        for (int j = 0; j < MATRIX_SIZE; j++) {
            for (int k = 0; k < MATRIX_SIZE; k++) {
                #pragma HLS PIPELINE II=1
                complex_t prod = complex_mult(A[i][k], B[k][j]);
                C[i][j] = complex_add(C[i][j], prod);
            }
        }
    }
}

// Apply rotation: A_new = U^H * A * U
static void apply_rotation(
    complex_t A[MATRIX_SIZE][MATRIX_SIZE],
    complex_t U[MATRIX_SIZE][MATRIX_SIZE],
    complex_t temp[MATRIX_SIZE][MATRIX_SIZE],
    complex_t A_out[MATRIX_SIZE][MATRIX_SIZE]
) {
    #pragma HLS INLINE off

    // Create U^H (conjugate transpose)
    complex_t UH[MATRIX_SIZE][MATRIX_SIZE];
    #pragma HLS ARRAY_PARTITION variable=UH dim=0 complete

    for (int i = 0; i < MATRIX_SIZE; i++) {
        for (int j = 0; j < MATRIX_SIZE; j++) {
            #pragma HLS PIPELINE II=1
            UH[i][j] = complex_conj(U[j][i]);
        }
    }

    // temp = A * U
    matrix_mult(A, U, temp);

    // A_out = U^H * temp
    matrix_mult(UH, temp, A_out);
}

void kernel_top(
    const ap_int<TOTAL_BITS> matrix_real_in[MATRIX_SIZE * MATRIX_SIZE],
    const ap_int<TOTAL_BITS> matrix_imag_in[MATRIX_SIZE * MATRIX_SIZE],
    ap_int<TOTAL_BITS> eigenvalues_real_out[MATRIX_SIZE],
    ap_int<TOTAL_BITS> eigenvalues_imag_out[MATRIX_SIZE],
    ap_int<TOTAL_BITS> eigenvectors_real_out[MATRIX_SIZE * MATRIX_SIZE],
    ap_int<TOTAL_BITS> eigenvectors_imag_out[MATRIX_SIZE * MATRIX_SIZE],
    ap_uint<12>& iter_count,
    ap_uint<32>& cycles
) {
    // Interface pragmas
    #pragma HLS INTERFACE mode=m_axi port=matrix_real_in bundle=gmem0 depth=100
    #pragma HLS INTERFACE mode=m_axi port=matrix_imag_in bundle=gmem1 depth=100
    #pragma HLS INTERFACE mode=m_axi port=eigenvalues_real_out bundle=gmem2 depth=10
    #pragma HLS INTERFACE mode=m_axi port=eigenvalues_imag_out bundle=gmem3 depth=10
    #pragma HLS INTERFACE mode=m_axi port=eigenvectors_real_out bundle=gmem4 depth=100
    #pragma HLS INTERFACE mode=m_axi port=eigenvectors_imag_out bundle=gmem5 depth=100
    #pragma HLS INTERFACE mode=s_axilite port=iter_count
    #pragma HLS INTERFACE mode=s_axilite port=cycles
    #pragma HLS INTERFACE mode=s_axilite port=return

    // Local matrices
    complex_t A[MATRIX_SIZE][MATRIX_SIZE];
    complex_t V[MATRIX_SIZE][MATRIX_SIZE];
    complex_t U[MATRIX_SIZE][MATRIX_SIZE];
    complex_t temp[MATRIX_SIZE][MATRIX_SIZE];
    complex_t A_new[MATRIX_SIZE][MATRIX_SIZE];

    #pragma HLS ARRAY_PARTITION variable=A dim=0 complete
    #pragma HLS ARRAY_PARTITION variable=V dim=0 complete
    #pragma HLS ARRAY_PARTITION variable=U dim=0 complete

    ap_uint<32> cycle_count = 0;

    // Load input matrix A
    for (int i = 0; i < MATRIX_SIZE; i++) {
        for (int j = 0; j < MATRIX_SIZE; j++) {
            #pragma HLS PIPELINE II=1
            int idx = i * MATRIX_SIZE + j;
            A[i][j].re = int_to_fixed(matrix_real_in[idx]);
            A[i][j].im = int_to_fixed(matrix_imag_in[idx]);
        }
    }
    cycle_count += MATRIX_SIZE * MATRIX_SIZE;

    // Initialize V as identity matrix
    for (int i = 0; i < MATRIX_SIZE; i++) {
        for (int j = 0; j < MATRIX_SIZE; j++) {
            #pragma HLS PIPELINE II=1
            if (i == j) {
                V[i][j].re = 1.0;
                V[i][j].im = 0.0;
            } else {
                V[i][j].re = 0.0;
                V[i][j].im = 0.0;
            }
        }
    }
    cycle_count += MATRIX_SIZE * MATRIX_SIZE;

    // Jacobi iteration
    ap_uint<12> z;
    for (z = 0; z < MAX_ITERATIONS; z++) {
        #pragma HLS LOOP_TRIPCOUNT min=10 max=100 avg=50

        // Find maximum off-diagonal element
        fixed_t off_diag_max = 0;
        ap_uint<4> p = 0;
        ap_uint<4> q = 1;

        for (int i = 0; i < MATRIX_SIZE; i++) {
            for (int j = i + 1; j < MATRIX_SIZE; j++) {
                #pragma HLS PIPELINE II=1
                fixed_t abs_val = complex_abs(A[i][j]);
                if (abs_val > off_diag_max) {
                    off_diag_max = abs_val;
                    p = i;
                    q = j;
                }
            }
        }
        cycle_count += (MATRIX_SIZE * (MATRIX_SIZE + 1)) / 2;

        // Check convergence
        if (off_diag_max < CONVERGENCE_THRESHOLD) {
            break;
        }

        // Get pivot elements
        complex_t a_pp = A[p][p];
        complex_t a_qq = A[q][q];
        complex_t a_pq = A[p][q];

        // Calculate rotation parameters
        // theta = 0.5 * arctan(2*|a_pq| / (a_pp - a_qq))
        // Note: for Hermitian matrices, a_pp and a_qq should be real
        fixed_t abs_a_pq = complex_abs(a_pq);
        fixed_t diff = a_pp.re - a_qq.re;

        fixed_t theta;
        if (hls::abs((float)diff) < 1e-10) {
            theta = 0.785398163;  // pi/4 in fixed-point
        } else {
            float theta_f = 0.5f * hls::atan(2.0f * (float)abs_a_pq / (float)diff);
            theta = theta_f;
        }

        // phi = -angle(a_pq)
        fixed_t phi = -complex_angle(a_pq);

        // Compute sin/cos
        fixed_t cos_theta = hls::cos((float)theta);
        fixed_t sin_theta = hls::sin((float)theta);
        fixed_t cos_phi = hls::cos((float)phi);
        fixed_t sin_phi = hls::sin((float)phi);

        cycle_count += 20;  // Estimate for trig operations

        // Build rotation matrix U as identity
        for (int i = 0; i < MATRIX_SIZE; i++) {
            for (int j = 0; j < MATRIX_SIZE; j++) {
                #pragma HLS PIPELINE II=1
                if (i == j) {
                    U[i][j].re = 1.0;
                    U[i][j].im = 0.0;
                } else {
                    U[i][j].re = 0.0;
                    U[i][j].im = 0.0;
                }
            }
        }

        // Set rotation elements
        // U[p,p] = cos(theta)
        U[p][p].re = cos_theta;
        U[p][p].im = 0;

        // U[p,q] = sin(theta) * exp(-j*phi) = sin(theta) * (cos(phi) - j*sin(phi))
        U[p][q].re = sin_theta * cos_phi;
        U[p][q].im = -sin_theta * sin_phi;

        // U[q,p] = sin(theta) * exp(j*phi) = sin(theta) * (cos(phi) + j*sin(phi))
        U[q][p].re = sin_theta * cos_phi;
        U[q][p].im = sin_theta * sin_phi;

        // U[q,q] = cos(theta) (corrected from reference bug)
        U[q][q].re = cos_theta;
        U[q][q].im = 0;

        cycle_count += MATRIX_SIZE * MATRIX_SIZE;

        // Apply rotation: A = U^H * A * U
        apply_rotation(A, U, temp, A_new);

        // Copy A_new to A
        for (int i = 0; i < MATRIX_SIZE; i++) {
            for (int j = 0; j < MATRIX_SIZE; j++) {
                #pragma HLS PIPELINE II=1
                A[i][j] = A_new[i][j];
            }
        }

        // Explicitly zero out pivoted elements
        A[p][q].re = 0;
        A[p][q].im = 0;
        A[q][p].re = 0;
        A[q][p].im = 0;

        cycle_count += MATRIX_SIZE * MATRIX_SIZE * MATRIX_SIZE * 3;  // Matrix mult estimate

        // Update eigenvectors: V = V * U
        matrix_mult(V, U, temp);
        for (int i = 0; i < MATRIX_SIZE; i++) {
            for (int j = 0; j < MATRIX_SIZE; j++) {
                #pragma HLS PIPELINE II=1
                V[i][j] = temp[i][j];
            }
        }

        cycle_count += MATRIX_SIZE * MATRIX_SIZE * MATRIX_SIZE + MATRIX_SIZE * MATRIX_SIZE;
    }

    // Extract eigenvalues (diagonal of A)
    for (int i = 0; i < MATRIX_SIZE; i++) {
        #pragma HLS PIPELINE II=1
        eigenvalues_real_out[i] = fixed_to_int(A[i][i].re);
        eigenvalues_imag_out[i] = fixed_to_int(A[i][i].im);
    }
    cycle_count += MATRIX_SIZE;

    // Write eigenvectors
    for (int i = 0; i < MATRIX_SIZE; i++) {
        for (int j = 0; j < MATRIX_SIZE; j++) {
            #pragma HLS PIPELINE II=1
            int idx = i * MATRIX_SIZE + j;
            eigenvectors_real_out[idx] = fixed_to_int(V[i][j].re);
            eigenvectors_imag_out[idx] = fixed_to_int(V[i][j].im);
        }
    }
    cycle_count += MATRIX_SIZE * MATRIX_SIZE;

    iter_count = z;
    cycles = cycle_count;
}

#include "kernel.h"
#include <iostream>
#include <fstream>
#include <iomanip>
#include <cstdlib>
#include <string>

using namespace std;

int main() {
    // Input and output arrays
    ap_int<TOTAL_BITS> matrix_real_in[MATRIX_SIZE * MATRIX_SIZE];
    ap_int<TOTAL_BITS> matrix_imag_in[MATRIX_SIZE * MATRIX_SIZE];
    ap_int<TOTAL_BITS> eigenvalues_real_out[MATRIX_SIZE];
    ap_int<TOTAL_BITS> eigenvalues_imag_out[MATRIX_SIZE];
    ap_int<TOTAL_BITS> eigenvectors_real_out[MATRIX_SIZE * MATRIX_SIZE];
    ap_int<TOTAL_BITS> eigenvectors_imag_out[MATRIX_SIZE * MATRIX_SIZE];
    ap_uint<12> iter_count;
    ap_uint<32> cycles;

    // Read input matrix from reference_inputs.txt
    ifstream infile("../reference_inputs.txt");
    if (!infile.is_open()) {
        cerr << "Error: Could not open ../reference_inputs.txt" << endl;
        return 1;
    }

    cout << "Reading input matrix..." << endl;

    int line_num;
    long long re_val, im_val;
    char separator;
    string line;
    int elements_read = 0;

    while (getline(infile, line) && elements_read < MATRIX_SIZE * MATRIX_SIZE) {
        // Parse line format: "  N|re im"
        size_t pipe_pos = line.find('|');
        if (pipe_pos == string::npos) continue;

        string data_part = line.substr(pipe_pos + 1);
        istringstream iss(data_part);

        if (iss >> re_val >> im_val) {
            matrix_real_in[elements_read] = re_val;
            matrix_imag_in[elements_read] = im_val;
            elements_read++;
        }
    }
    infile.close();

    if (elements_read != MATRIX_SIZE * MATRIX_SIZE) {
        cerr << "Error: Expected " << MATRIX_SIZE * MATRIX_SIZE 
             << " elements, read " << elements_read << endl;
        return 1;
    }

    cout << "Successfully read " << elements_read << " complex elements" << endl;

    // Print first few input elements for verification
    cout << "\nFirst 10 input elements:" << endl;
    for (int i = 0; i < min(10, MATRIX_SIZE * MATRIX_SIZE); i++) {
        cout << "  [" << i << "] = " 
             << matrix_real_in[i].to_int64() << " + " 
             << matrix_imag_in[i].to_int64() << "j" << endl;
    }

    // Run the kernel
    cout << "\nRunning kernel_top..." << endl;
    kernel_top(
        matrix_real_in,
        matrix_imag_in,
        eigenvalues_real_out,
        eigenvalues_imag_out,
        eigenvectors_real_out,
        eigenvectors_imag_out,
        iter_count,
        cycles
    );

    cout << "Kernel completed!" << endl;
    cout << "Iterations: " << iter_count.to_uint() << endl;
    cout << "Cycles: " << cycles.to_uint() << endl;

    // Create sim directory if it doesn't exist
    system("mkdir -p ../sim");

    // Write diagonal outputs (eigenvalues) to sim/sim_diag_out.txt
    ofstream diagfile("../sim/sim_diag_out.txt");
    if (!diagfile.is_open()) {
        cerr << "Error: Could not create ../sim/sim_diag_out.txt" << endl;
        return 1;
    }

    cout << "\nEigenvalues (diagonal):" << endl;
    for (int i = 0; i < MATRIX_SIZE; i++) {
        long long re = eigenvalues_real_out[i].to_int64();
        long long im = eigenvalues_imag_out[i].to_int64();
        diagfile << re << " " << im << endl;
        cout << "  λ[" << i << "] = " << re << " + " << im << "j" << endl;
    }
    diagfile.close();
    cout << "Wrote eigenvalues to ../sim/sim_diag_out.txt" << endl;

    // Write metadata to sim/sim_meta.txt
    ofstream metafile("../sim/sim_meta.txt");
    if (!metafile.is_open()) {
        cerr << "Error: Could not create ../sim/sim_meta.txt" << endl;
        return 1;
    }

    metafile << "iter_count " << iter_count.to_uint() << endl;
    metafile << "cycles " << cycles.to_uint() << endl;
    metafile.close();
    cout << "Wrote metadata to ../sim/sim_meta.txt" << endl;

    // Optionally write eigenvectors for debugging
    ofstream vecfile("../sim/sim_eigenvectors.txt");
    if (vecfile.is_open()) {
        for (int i = 0; i < MATRIX_SIZE * MATRIX_SIZE; i++) {
            vecfile << eigenvectors_real_out[i].to_int64() << " "
                    << eigenvectors_imag_out[i].to_int64() << endl;
        }
        vecfile.close();
        cout << "Wrote eigenvectors to ../sim/sim_eigenvectors.txt" << endl;
    }

    cout << "\nTestbench completed successfully!" << endl;
    return 0;
}
